/* Main entry point for firmware update task */
void fw_update_task(void *pvParameter)
{
    const char *url = (const char *)pvParameter;
    fw_error_t result;

    ESP_LOGI(TAG, "Firmware update task started");

    result = fw_update_perform(url);

    if (result != FW_OK) {
        ESP_LOGE(TAG, "Firmware update failed: %s", fw_error_str(result));
    }

    /* Task should not reach here on success (device reboots) */
    vTaskDelete(NULL);
}

